/**
 * Metric query translation to DQL.
 */
export interface MetricQueryDQLTranslation {
    /**
     * Error message - only present if the status is `not supported`
     */
    message?: string;
    /**
     * The DQL query corresponding to the metric query
     */
    query?: string;
    /**
     * The status of the DQL translation, either `success` or `not supported`
     */
    status?: 'not supported' | 'success';
}
